using System.IO.Abstractions;

namespace MyApp.Services;

/// <summary>
/// Convenience wrapper over <see cref="IFileSystem"/> that provides
/// common file and directory operations with built-in guard checks.
/// </summary>
public interface IFileSystemWrapper
{
    // File operations
    string ReadAllText(string path);
    byte[] ReadAllBytes(string path);
    string[] ReadAllLines(string path);
    void WriteAllText(string path, string content);
    void WriteAllBytes(string path, byte[] bytes);
    void WriteAllLines(string path, IEnumerable<string> lines);
    Stream OpenRead(string path);
    Stream Create(string path);
    void CopyFile(string source, string destination, bool overwrite = false);
    void MoveFile(string source, string destination, bool overwrite = false);
    void DeleteFile(string path);
    bool FileExists(string path);

    // Directory operations
    void CreateDirectory(string path);
    void DeleteDirectory(string path, bool recursive = false);
    bool DirectoryExists(string path);
    IEnumerable<string> EnumerateFiles(string path, string searchPattern = "*", SearchOption searchOption = SearchOption.TopDirectoryOnly);
    IEnumerable<string> EnumerateDirectories(string path, string searchPattern = "*", SearchOption searchOption = SearchOption.TopDirectoryOnly);

    // Path operations
    string Combine(params string[] paths);
    string GetDirectoryName(string path);
    string GetFileName(string path);
    string GetFullPath(string path);
    string GetTempPath();

    // Convenience helpers
    void EnsureDirectoryExists(string path);
    void EnsureParentDirectoryExists(string filePath);
    string ReadAllTextIfExists(string path, string defaultValue = "");
}

public class FileSystemWrapper(IFileSystem fileSystem) : IFileSystemWrapper
{
    // File operations

    public string ReadAllText(string path) => fileSystem.File.ReadAllText(path);

    public byte[] ReadAllBytes(string path) => fileSystem.File.ReadAllBytes(path);

    public string[] ReadAllLines(string path) => fileSystem.File.ReadAllLines(path);

    public void WriteAllText(string path, string content) => fileSystem.File.WriteAllText(path, content);

    public void WriteAllBytes(string path, byte[] bytes) => fileSystem.File.WriteAllBytes(path, bytes);

    public void WriteAllLines(string path, IEnumerable<string> lines) => fileSystem.File.WriteAllLines(path, lines);

    public Stream OpenRead(string path) => fileSystem.File.OpenRead(path);

    public Stream Create(string path) => fileSystem.File.Create(path);

    public void CopyFile(string source, string destination, bool overwrite = false) =>
        fileSystem.File.Copy(source, destination, overwrite);

    public void MoveFile(string source, string destination, bool overwrite = false)
    {
        if (overwrite && fileSystem.File.Exists(destination))
            fileSystem.File.Delete(destination);

        fileSystem.File.Move(source, destination);
    }

    public void DeleteFile(string path)
    {
        if (fileSystem.File.Exists(path))
            fileSystem.File.Delete(path);
    }

    public bool FileExists(string path) => fileSystem.File.Exists(path);

    // Directory operations

    public void CreateDirectory(string path) => fileSystem.Directory.CreateDirectory(path);

    public void DeleteDirectory(string path, bool recursive = false) =>
        fileSystem.Directory.Delete(path, recursive);

    public bool DirectoryExists(string path) => fileSystem.Directory.Exists(path);

    public IEnumerable<string> EnumerateFiles(string path, string searchPattern = "*", SearchOption searchOption = SearchOption.TopDirectoryOnly) =>
        fileSystem.Directory.EnumerateFiles(path, searchPattern, searchOption);

    public IEnumerable<string> EnumerateDirectories(string path, string searchPattern = "*", SearchOption searchOption = SearchOption.TopDirectoryOnly) =>
        fileSystem.Directory.EnumerateDirectories(path, searchPattern, searchOption);

    // Path operations

    public string Combine(params string[] paths) => fileSystem.Path.Combine(paths);

    public string GetDirectoryName(string path) => fileSystem.Path.GetDirectoryName(path)!;

    public string GetFileName(string path) => fileSystem.Path.GetFileName(path);

    public string GetFullPath(string path) => fileSystem.Path.GetFullPath(path);

    public string GetTempPath() => fileSystem.Path.GetTempPath();

    // Convenience helpers

    public void EnsureDirectoryExists(string path)
    {
        if (!fileSystem.Directory.Exists(path))
            fileSystem.Directory.CreateDirectory(path);
    }

    public void EnsureParentDirectoryExists(string filePath)
    {
        var dir = fileSystem.Path.GetDirectoryName(filePath);
        if (dir is not null && !fileSystem.Directory.Exists(dir))
            fileSystem.Directory.CreateDirectory(dir);
    }

    public string ReadAllTextIfExists(string path, string defaultValue = "") =>
        fileSystem.File.Exists(path) ? fileSystem.File.ReadAllText(path) : defaultValue;
}

